question.en:
What will be logged to the console?
js
const parent = document.getElementById('parent');
parent.addEventListener('click', (e) => {
  if (e.target.classList.contains('item')) {
    console.log('Item clicked:', e.target.textContent);
  }
});
// User clicks on a newly added element with class 'item'
const newItem = document.createElement('div');
newItem.className = 'item';
newItem.textContent = 'Dynamic';
parent.appendChild(newItem);
// User then clicks on newItem

question.ru:
Что будет выведено в консоль?
js
const parent = document.getElementById('parent');
parent.addEventListener('click', (e) => {
  if (e.target.classList.contains('item')) {
    console.log('Item clicked:', e.target.textContent);
  }
});
// Пользователь нажимает на недавно добавленный элемент с классом 'item'
const newItem = document.createElement('div');
newItem.className = 'item';
newItem.textContent = 'Dynamic';
parent.appendChild(newItem);
// Пользователь затем нажимает на newItem

